394	/* ── Modals ──────────────────────────────────────────────────────────── */
395	.overlay {
396	  position: fixed;
397	  inset: 0;
398	  background: rgba(0,0,0,.45);
399	  z-index: 400;
400	  display: flex;
401	  align-items: center;
402	  justify-content: center;
403	  backdrop-filter: blur(2px);
404	}
405	
406	.modal {
407	  background: #fff;
408	  border-radius: 16px;
409	  width: 540px;
410	  max-width: 92vw;
411	  max-height: 90vh;
412	  overflow: hidden;
413	  display: flex;
414	  flex-direction: column;
415	  box-shadow: 0 20px 60px rgba(0,0,0,.25);
416	}
417	
418	.modalHeader {
419	  padding: 18px 22px;
420	  border-bottom: 1px solid #f1f5f9;
421	  display: flex;
422	  align-items: center;
423	  justify-content: space-between;
424	  position: sticky;
425	  top: 0;
426	  background: #fff;
427	  z-index: 1;
428	}
429	
430	.modalTitle {
431	  font-size: 15px;
432	  font-weight: 700;
433	  color: #1d1d1f;
434	}
435	
436	.modalClose {
437	  width: 28px;
438	  height: 28px;
439	  background: #f1f5f9;
440	  border: none;
441	  border-radius: 6px;
442	  cursor: pointer;
443	  font-size: 15px;
444	  color: #6e6e73;
445	  display: flex;
446	  align-items: center;
447	  justify-content: center;
448	}
449	
450	.modalClose:hover { background: #e2e8f0; }
451	
452	.modalBody {
453	  padding: 18px 22px;
454	  overflow-y: auto;
455	  flex: 1;
456	}
457	
458	/* ── Confirm box ─────────────────────────────────────────────────────── */
459	.confirmBox {
460	  background: #fff;
461	  border-radius: 16px;
462	  padding: 28px 24px;
463	  width: 360px;
464	  max-width: 90vw;
465	  box-shadow: 0 20px 60px rgba(0,0,0,.3);
466	  text-align: center;
467	}
468	
469	.confirmMsg {
470	  font-size: 14px;
471	  color: #374151;
472	  margin-bottom: 22px;
473	  line-height: 1.6;
474	}
475	
476	.confirmBtns {
477	  display: flex;
478	  gap: 10px;
479	  justify-content: center;
480	}
481	
482	/* ── Toast ───────────────────────────────────────────────────────────── */
483	.toast {
484	  position: fixed;
485	  bottom: 24px;
486	  right: 24px;
487	  padding: 11px 18px;
488	  border-radius: 10px;
489	  font-size: 13px;
490	  font-weight: 500;
491	  display: flex;
492	  align-items: center;
493	  gap: 8px;
494	  box-shadow: 0 4px 20px rgba(0,0,0,.2);
495	  z-index: 9999;
496	  animation: slideUp .2s ease;
497	  color: #fff;
498	}
499	
500	.toast_info    { background: #1e293b; }
501	.toast_success { background: #059669; }
502	.toast_error   { background: #dc2626; }
503	
504	@keyframes slideUp {
505	  from { transform: translateY(12px); opacity: 0; }
506	  to   { transform: translateY(0);    opacity: 1; }
507	}
508	
509	/* ── Responsive ──────────────────────────────────────────────────────── */
510	@media (max-width: 900px) {
511	  .wrap { flex-direction: column; }
512	  .leftPanelNarrow { width: 100%; }
513	}
