        UPDATE NumuneX4
        SET LimitDeger=@limitDeger, LimitBirimi=@limitBirimi, Notlar=@notlar
        WHERE ID=@itemId AND ListeID=@listeId
      `);

    return NextResponse.json({ ok: true });
  } catch (err: any) {
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

